code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Table, Checkbox, Button, Input, Badge, icon } from 'decantr/components';

code.example:
function DataTable({ search, status, data }) {
  const { div, span, thead, tbody, tr, th, td } = tags;

  const columns = [
    { key: 'name', label: 'Name', sortable: true },
    { key: 'status', label: 'Status', sortable: true },
    { key: 'email', label: 'Email', sortable: false },
    { key: 'amount', label: 'Amount', sortable: true },
  ];

  const rows = data || [
    { name: 'Alice Johnson', status: 'active', email: 'alice@example.com', amount: '$1,200' },
    { name: 'Bob Smith', status: 'inactive', email: 'bob@example.com', amount: '$890' },
    { name: 'Carol White', status: 'active', email: 'carol@example.com', amount: '$2,100' },
  ];

  return div({ class: css('_flex _col _gap4 _w[100%] _overflow[auto]') },
    div({ class: css('_flex _jcsb _aic _gap4') },
      Input({ placeholder: 'Search...', value: search || '', class: css('_mw[300px]') }),
      div({ class: css('_flex _gap2') },
        Button({ variant: 'outline', size: 'sm' }, icon('download'), 'Export'),
        Button({ variant: 'outline', size: 'sm' }, icon('trash'), 'Delete')
      )
    ),
    Table({ class: css('_w[100%]') },
      thead({},
        tr({},
          th({ class: css('_p3') }, Checkbox({})),
          ...columns.map(col =>
            th({ class: css('_p3 _textleft _textsm _fgmuted') },
              span({}, col.label),
              col.sortable ? icon('chevrons-up-down', { size: '0.75rem', class: css('_ml1') }) : null
            )
          )
        )
      ),
      tbody({},
        ...rows.map(row =>
          tr({ class: css('_borderbottom _border[var(--border)]') },
            td({ class: css('_p3') }, Checkbox({})),
            td({ class: css('_p3 _textsm _fontmedium') }, row.name),
            td({ class: css('_p3') }, Badge({ variant: row.status === 'active' ? 'default' : 'secondary' }, row.status)),
            td({ class: css('_p3 _textsm') }, row.email),
            td({ class: css('_p3 _textsm _textright') }, row.amount)
          )
        )
      )
    ),
    div({ class: css('_flex _jcsb _aic _py2') },
      span({ class: css('_textsm _fgmuted') }, `${rows.length} row(s)`),
      div({ class: css('_flex _gap2') },
        Button({ variant: 'outline', size: 'sm', disabled: true }, 'Previous'),
        Button({ variant: 'outline', size: 'sm' }, 'Next')
      )
    )
  );
}

